//Envio el XML al Server
function sendToServer()
{
	proxy=new NomadProxy();
	proxy.StoreService().SetSessionStore("IDSLegajos", array2string(arrA));
	return true;
}

function ACCEPT()
{
	sendToServer();
}

function CANCEL()
{
	Ctrl("main").DoEvent("CANCEL");
}

function EncodeXML(xmlin)
{	
	xmlin = Replace(xmlin, "&", "&amp;");
	xmlin = Replace(xmlin, "<", "&lt;");
	xmlin = Replace(xmlin, ">", "&gt;");
	xmlin = Replace(xmlin, "'", "´");
	xmlin = Replace(xmlin, '"', "&quot;");

	return xmlin;
}  

//Habilita y desmarca el CheckBox l_afiliado_sind cuando hay un sindicato seleccionado
//Desmarca y deshabilita el checkbox l_afiliado_sind cuando no hay un sindicato seleccionado
function habilitarAfiliado()
{
	//Desmarca el Checck.
	if (Ctrl("sindicato").GetXValue()=='') Ctrl('l_afiliado_sind').SetXValue(0);
	Ctrl('l_afiliado_sind').SetEnabled(Ctrl("sindicato").GetXValue()!='');
}

