{%?('##forma_pago##'!='') {% and LEG.oi_forma_pago = ##forma_pago## %} {% %} %}			
{%?('##fecha_desde##'!='') {% and LEG.f_ingreso >= {Datetime(\'##fecha_desde##\')} %} {% %} %}
{%?('##fecha_hasta##'!='') {% and LEG.f_ingreso <= {Datetime(\'##fecha_hasta##\')} %} {% %} %}
{%? ('##cb_confidenciales##'!='' and '##cb_confidenciales##'!='T' ) 
{%  
